import anthropic, json, os, subprocess

client = anthropic.Anthropic()

# Tool implementations — these produce real effects
def read_file(path: str) -> str:
    try:
        with open(path) as f:
            return f.read()
    except Exception as e:
        return f"Error: {e}"

def write_file(path: str, content: str) -> str:
    try:
        with open(path, "w") as f:
            f.write(content)
        return f"Written {len(content)} bytes to {path}"
    except Exception as e:
        return f"Error: {e}"

def run_shell(command: str) -> str:
    result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30)
    return result.stdout + result.stderr

TOOLS = [
    {"name": "read_file", "description": "Read a file from disk",
     "input_schema": {"type": "object", "properties": {"path": {"type": "string"}}, "required": ["path"]}},
    {"name": "write_file", "description": "Write content to a file",
     "input_schema": {"type": "object", "properties": {"path": {"type": "string"}, "content": {"type": "string"}}, "required": ["path", "content"]}},
    {"name": "run_shell", "description": "Run a shell command",
     "input_schema": {"type": "object", "properties": {"command": {"type": "string"}}, "required": ["command"]}},
]
TOOL_REGISTRY = {"read_file": read_file, "write_file": write_file, "run_shell": run_shell}

def run_agent(goal: str, max_steps: int = 20) -> str:
    messages = [{"role": "user", "content": goal}]
    system = "You are an autonomous coding assistant. Use tools to complete the requested task."

    for step in range(max_steps):
        response = client.messages.create(
            model="claude-opus-4-8", max_tokens=2048,
            system=system, tools=TOOLS, messages=messages
        )
        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if hasattr(b, "text")), "Done.")

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                print(f"[step {step+1}] {block.name}({block.input})")
                result = TOOL_REGISTRY[block.name](**block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

    return "Step limit reached."

# The agent autonomously reads, modifies, and tests code without further user input
print(run_agent("Read main.py, add type hints to all function signatures, then run pytest to verify nothing broke."))

import anthropic, json

client = anthropic.Anthropic()

# Simulated data sources
def get_sales_data(month: str) -> dict:
    return {"month": month, "revenue": 142300, "deals_closed": 47, "avg_deal_size": 3028}

def get_churn_data(month: str) -> dict:
    return {"month": month, "churned_customers": 8, "churn_rate_pct": 1.4}

def write_report(filename: str, content: str) -> str:
    with open(filename, "w") as f:
        f.write(content)
    return f"Report written to {filename}"

TOOLS = [
    {"name": "get_sales_data", "description": "Fetch monthly sales data",
     "input_schema": {"type": "object", "properties": {"month": {"type": "string"}}, "required": ["month"]}},
    {"name": "get_churn_data", "description": "Fetch monthly churn data",
     "input_schema": {"type": "object", "properties": {"month": {"type": "string"}}, "required": ["month"]}},
    {"name": "write_report", "description": "Write a report to disk",
     "input_schema": {"type": "object", "properties": {"filename": {"type": "string"}, "content": {"type": "string"}}, "required": ["filename", "content"]}},
]
TOOL_REGISTRY = {"get_sales_data": get_sales_data, "get_churn_data": get_churn_data, "write_report": write_report}

def run_report_agent(goal: str) -> str:
    messages = [{"role": "user", "content": goal}]
    for _ in range(10):
        r = client.messages.create(model="claude-opus-4-8", max_tokens=2048, tools=TOOLS, messages=messages)
        if r.stop_reason == "end_turn":
            return next(b.text for b in r.content if hasattr(b, "text"))
        results = []
        for b in r.content:
            if b.type == "tool_use":
                out = TOOL_REGISTRY[b.name](**b.input)
                results.append({"type": "tool_result", "tool_use_id": b.id, "content": json.dumps(out)})
        messages += [{"role": "assistant", "content": r.content}, {"role": "user", "content": results}]
    return "Limit reached."

print(run_report_agent("Compile the June 2025 sales and churn report and save it as june_report.md"))

